type CheckoutEvent = {
  orderId: string
  items: Array<{ sku: string; qty: number; unitPriceCents: number }>
  customer: { email: string }
}

function isCheckoutEvent(value: unknown): value is CheckoutEvent {
  if (!value || typeof value !== 'object') return false
  const candidate = value as Partial<CheckoutEvent>
  return typeof candidate.orderId === 'string' && Array.isArray(candidate.items)
}

declare const rawBody: string
const event = JSON.parse(rawBody) as unknown
if (!isCheckoutEvent(event)) {
  throw new Error('Invalid checkout payload')
}

const totalCents = event.items.reduce((sum, item) => sum + item.qty * item.unitPriceCents, 0)
//    ^?

const firstSku = event.items[0]?.sku
